        };

        // Convert inline Markdown to HTML — code backticks processed first to protect content
        $inline = function($text) use ($esc) {
            // Step 1: Extract code spans and replace with placeholders
            $code_spans = [];
            $text = preg_replace_callback('/`([^`]+)`/', function($m) use (&$code_spans, $esc) {
                $idx = count($code_spans);
                $code_spans[] = '<code>' . $esc($m[1]) . '</code>';
                return "\x00CODE{$idx}\x00";
            }, $text);
            
            // Step 2: Apply other inline formatting
            // Images: ![alt](src)
            $text = preg_replace_callback('/!\[([^\]]*)\]\(([^)]+)\)/', function($m) use ($esc) {
                return '<img src="' . $esc($m[2]) . '" alt="' . $esc($m[1]) . '">';
