                }
                $bq_text = implode("\n", $bq_lines);
                $bq_paras = preg_split('/\n\n+/', trim($bq_text));
                $html .= "<blockquote>\n";
                foreach ($bq_paras as $bp) {
                    if (trim($bp) !== '') {
                        $html .= "<p>" . $inline(trim($bp)) . "</p>\n";
                    }
                }
                $html .= "</blockquote>\n\n";
                continue;
            }
            
            // Tables
            if (strpos($line, '|') !== false && preg_match('/^\|/', $line)) {
                $rows = [];
                while ($i < count($lines)) {
                    $tl = rtrim($lines[$i]);
                    if (!preg_match('/^\|/', $tl)) break;
                    $cells = array_map('trim', explode('|', trim($tl, '|')));
                    
                    // Skip separator row (|---|---|)
                    if (preg_match('/^[\s\|:-]+$/', str_replace('|', '', implode('', $cells)))) {
                        $i++;
                        continue;
                    }
                    $rows[] = $cells;
                    $i++;
